import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / trivial quotes ---
  it.todo("empty item list → premium 5 G (only processing fee)");

  // --- Single main items (base + fee + first-insurance for newcomer with no contracts) ---
  // We isolate base behavior using a long-standing customer on a follow-up contract where applicable,
  // but to keep tests focused on individual rules, we use the spec's integration examples for stacking.

  // --- Base premiums per item type (newcomer, no curse, no enchant) ---
  // For a newcomer (0 years) with one quote/item: base + 10% first insurance + 5 fee
  it.todo("newcomer single plain sword → 115 G (100 base + 10 first-insurance + 5 fee)");
  it.todo("newcomer single plain amulet → 71 G (60 base + 6 first-insurance + 5 fee)");
  it.todo("newcomer single plain staff → 93 G (80 base + 8 first-insurance + 5 fee)");
  it.todo("newcomer single plain potion → 49 G (40 base + 4 first-insurance + 5 fee)");

  // --- Components & blocks ---
  it.todo("2 runes → 50 G base premium (no block)");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium");
  it.todo("'Alike' components: 2 runes + 1 moonstone → 75 G base premium (no block, different types)");
  it.todo("'Alike' components: 3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // --- Modifier scope on multi-item policies ---
  it.todo(
    "cursed sword + plain amulet policy → policy base 160 + curse 50 (50% of cursed sword's base) = 210 G before further modifiers and fee",
  );
  // policy with single cursed sword for a long-standing customer on second contract from spec example below

  // --- Modifier thresholds ---
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("cursed sword with exactly enchantment 5 → both curse and high-enchantment surcharges apply");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge; plain sword behaves normally");

  // --- Rounding in MHPCO's favor ---
  it.todo("premium that yields 197.5 G → final premium 198 G (rounded up)");
  it.todo("payout that yields 350.5 G → final payout 350 G (rounded down)");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
  it.todo(
    "long-standing customer (3 years) second contract, cursed sword (steel, enchantment 7) → premium 160 G",
  );

  // --- Claim processing: standard reimbursement ---
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G");
  it.todo("damage to a rune (insurance 250 G), damage 200 G → payout 100 G (no special clauses)");

  // --- Claim processing: enchantment threshold vs. dragon material ---
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-ench then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement minus deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // --- Deductible per damage event ---
  it.todo(
    "dragon attack: insured sword damaged 500 G and insured amulet damaged 300 G → payout 600 G (deductible per item)",
  );

  // --- Multi-items of the same type ---
  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G");
  it.todo(
    "policy with two swords, dragon attack damages both → each damage entry treated separately with own deductible",
  );
  it.todo(
    "claim references more sword damages than the policy covers → CLI exits non-zero, whole claim rejected",
  );

  // --- Cap exhaustion ---
  it.todo("policy with sword + amulet: insurance sum 1600 G, cap 3200 G");
  it.todo("policy with cursed sword: cap 2000 G (based on unmodified insurance value)");
  it.todo("policy with sword + 3 runes: insurance sum 1750 G (block discount doesn't affect insurance sum)");
  it.todo(
    "sword insured (cap 2000 G): first claim 1500 G → payout 1400, remaining 600; second claim 1500 G → payout 600, remaining 0",
  );

  // --- Edge cases ---
  it.todo("quote with unknown item type → CLI exits non-zero with error to stderr; no results written");
  it.todo(
    "claim references damage for item not in policy (amulet damaged when only sword insured) → CLI exits non-zero",
  );
  it.todo("claim references damage with unknown item type → CLI exits non-zero");
  it.todo("claim contains damage with negative amount → CLI exits non-zero with error to stderr");

  // --- CLI shape ---
  it.todo("CLI reads JSON from stdin and writes JSON {results: [...]} to stdout (schema example)");
});

