interface QuoteItem {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface QuoteStep {
  op: "quote";
  items: QuoteItem[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

interface QuoteResult {
  premium: number;
}

interface ScenarioResult {
  results: QuoteResult[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

function calculateQuote(step: QuoteStep): QuoteResult {
  const policyBase = step.items.reduce(
    (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
    0,
  );
  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
  const premium = policyBase + firstInsurance + PROCESSING_FEE;
  return { premium };
}

export function runScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => calculateQuote(step));
  return { results };
}

